package main

import (
    "fmt"
    "reflect"
)

type Player struct {
    Name   string `json:"name"`
    Health int    `json:"health"`
    Attack int    `json:"attack"`
    Level  int    `json:"level"`
}

func main() {
    // ---- Type information ----
    p := Player{Name: "Hero", Health: 100, Attack: 20, Level: 5}

    t := reflect.TypeOf(p)
    fmt.Printf("Type: %s\n", t.Name())
    fmt.Printf("Kind: %s\n", t.Kind())
    fmt.Printf("Number of fields: %d\n", t.NumField())

    // ---- Field iteration ----
    fmt.Println("\n--- Fields ---")
    for i := 0; i < t.NumField(); i++ {
        field := t.Field(i)
        fmt.Printf("  %s: %s (tag: %s)\n", field.Name, field.Type, field.Tag.Get("json"))
    }

    // ---- Value iteration ----
    fmt.Println("\n--- Values ---")
    v := reflect.ValueOf(p)
    for i := 0; i < v.NumField(); i++ {
        fmt.Printf("  %s = %v\n", t.Field(i).Name, v.Field(i).Interface())
    }

    // ---- Modify values (via pointer) ----
    fmt.Println("\n--- Modifying ---")
    p2 := Player{Name: "Aragorn", Health: 120, Attack: 25, Level: 8}
    v2 := reflect.ValueOf(&p2).Elem()

    // Can we set the field?
    healthField := v2.FieldByName("Health")
    if healthField.CanSet() {
        healthField.SetInt(150)
    }
    fmt.Printf("Updated health: %d\n", p2.Health)

    // ---- Tags ----
    fmt.Println("\n--- Tags ---")
    field, _ := t.FieldByName("Name")
    fmt.Printf("Name tag: %s\n", field.Tag.Get("json"))

    // ---- Type checking ----
    fmt.Println("\n--- Type checking ---")
    var x interface{} = 42
    fmt.Printf("x type: %s\n", reflect.TypeOf(x))

    var y interface{} = "hello"
    fmt.Printf("y type: %s\n", reflect.TypeOf(y))

    // ---- Kind checks ----
    fmt.Println("\n--- Kind checks ---")
    switch reflect.TypeOf(x).Kind() {
    case reflect.Int:
        fmt.Println("x is an int")
    case reflect.String:
        fmt.Println("x is a string")
    }

    // ---- Creating struct from tags ----
    fmt.Println("\n--- JSON tags ---")
    for i := 0; i < t.NumField(); i++ {
        field := t.Field(i)
        jsonTag := field.Tag.Get("json")
        if jsonTag != "" {
            fmt.Printf("  %s -> %s\n", field.Name, jsonTag)
        }
    }
}

