package main

import (
    "fmt"
    "reflect"
)

type Player struct {
    Name   string
    Health int
    Attack int
    Level  int
}

func Inspect(v interface{}) {
    t := reflect.TypeOf(v)
    val := reflect.ValueOf(v)

    fmt.Printf("Type: %s\n", t.Name())
    fmt.Printf("Kind: %s\n", t.Kind())

    if t.Kind() == reflect.Struct {
        fmt.Printf("Number of fields: %d\n", t.NumField())
        for i := 0; i < t.NumField(); i++ {
            field := t.Field(i)
            value := val.Field(i)
            fmt.Printf("  %s: %s = %v\n", field.Name, field.Type, value.Interface())
        }
    }
    fmt.Println()
}

func main() {
    p := Player{Name: "Hero", Health: 100, Attack: 20, Level: 5}
    Inspect(p)
    Inspect(42)
}
